    "ra_Successfully authorized. Token valid till %s and will be automatically renewed.": "\u0410\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0456\u044E \u0443\u0441\u043F\u0456\u0448\u043D\u043E \u043F\u0440\u043E\u0439\u0448\u043B\u043E. \u0422\u043E\u043A\u0435\u043D \u0434\u0456\u0439\u0441\u043D\u0438\u0439 \u0434\u043E %s \u0442\u0430 \u0431\u0443\u0434\u0435 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u043D\u043E \u043F\u043E\u043D\u043E\u0432\u043B\u0435\u043D\u043E.",
    "ra_Successfully authorized. Token valid till %s but it can expire as the instance is not running.": "\u0410\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0456\u044E \u0443\u0441\u043F\u0456\u0448\u043D\u043E \u0432\u0438\u043A\u043E\u043D\u0430\u043D\u043E. \u0422\u043E\u043A\u0435\u043D \u0434\u0456\u0439\u0441\u043D\u0438\u0439 \u0434\u043E %s, \u0430\u043B\u0435 \u0439\u043E\u0433\u043E \u0442\u0435\u0440\u043C\u0456\u043D \u0434\u0456\u0457 \u043C\u043E\u0436\u0435 \u0437\u0430\u043A\u0456\u043D\u0447\u0438\u0442\u0438\u0441\u044F, \u043E\u0441\u043A\u0456\u043B\u044C\u043A\u0438 \u0435\u043A\u0437\u0435\u043C\u043F\u043B\u044F\u0440 \u043D\u0435 \u0437\u0430\u043F\u0443\u0449\u0435\u043D\u043E.",
    "ra_Suitable license not found in license manager": "\u0412\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0430 \u043B\u0456\u0446\u0435\u043D\u0437\u0456\u044F \u043D\u0435 \u0437\u043D\u0430\u0439\u0434\u0435\u043D\u0430 \u0432 \u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440\u0456 \u043B\u0456\u0446\u0435\u043D\u0437\u0456\u0439",
    ra_Sunday: MMe,
    "ra_Suppress question for next %s minutes": "\u041F\u0440\u0438\u0445\u043E\u0432\u0430\u0442\u0438 \u0437\u0430\u043F\u0438\u0442\u0430\u043D\u043D\u044F \u043D\u0430 \u043D\u0430\u0441\u0442\u0443\u043F\u043D\u0456 %s \u0445\u0432\u0438\u043B\u0438\u043D",
    "ra_System language": "\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u0430 \u043C\u043E\u0432\u0430",
    "ra_Take browser position": "\u0417\u0430\u0439\u043C\u0456\u0442\u044C \u043F\u043E\u0437\u0438\u0446\u0456\u044E \u0437 \u0431\u0440\u0430\u0443\u0437\u0435\u0440\u0430",
